validate_transition PROC
    ; RCX = current_state (int)
    ; RDX = next_state (int)
    ; R8  = prerequisites (uint64_t)

    ; Explicit bounds checking for current_state
    cmp ecx, 0
    jl invalid_transition
    cmp ecx, 7
    jg invalid_transition

    ; Explicit bounds checking for next_state
    cmp edx, 0
    jl invalid_transition
    cmp edx, 7
    jg invalid_transition

    ; Reset is always allowed
    test edx, edx
    jz valid_transition

    ; Check sequential progression
    mov eax, ecx
    inc eax
    cmp edx, eax
    jne invalid_transition

    ; Check prerequisites: bit (next_state - 1) must be set in R8
    ; Shift count must be in CL. We move next_state - 1 into ECX.
    mov ecx, edx
    dec ecx             ; ECX = next_state - 1

    mov rax, 1
    shl rax, cl         ; RAX = 1ULL << (next_state - 1)

    test r8, rax        ; Check if bit is set in prerequisites (R8)
    jz invalid_transition

valid_transition:
    mov eax, 1
    ret

invalid_transition:
    xor eax, eax
    ret
validate_transition ENDP

